137	fn daemon_default_features_exclude_gui() {
138	    let root = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
139	    let cargo_toml = root.join("Cargo.toml");
140	    let contents = std::fs::read_to_string(&cargo_toml).expect("failed to read Cargo.toml");
141	    // Parse [features] section to extract the default = [...] line.
142	    let in_features = &mut false;
143	    for line in contents.lines() {
144	        let trimmed = line.trim();
145	        if trimmed == "[features]" {
146	            *in_features = true;
147	            continue;
148	        }
149	        if *in_features {
150	            // Stop at next section header.
151	            if trimmed.starts_with('[') {
152	                break;
153	            }
154	            if trimmed.starts_with("default") {
155	                assert!(
156	                    !trimmed.contains("gui"),
157	                    "default features must not include 'gui', found: {trimmed}"
158	                );
159	                return;
160	            }
161	        }
162	    }
163	    // If we reach here, the default line was found and does not include "gui",
164	    // or the [features] section had no explicit default (which is also fine).
165	}
